// Quick test for vehicleDisplay helper
const testCases = [
  // Engine text - should NOT display
  { trim: "5.7i", expected: "" },
  { trim: "3.5L", expected: "" },
  { trim: "V8", expected: "" },
  { trim: "2.0T", expected: "" },
  { trim: "EcoBoost", expected: "" },

  // Real submodels - SHOULD display
  { trim: "Z28", expected: "Z28" },
  { trim: "SS", expected: "SS" },
  { trim: "Base", expected: "Base" },
  { trim: "XLT", expected: "XLT" },
  { trim: "Lariat", expected: "Lariat" },
  { trim: "GT", expected: "GT" },
  { trim: "Rubicon", expected: "Rubicon" },

  // Combined - should extract submodel
  { trim: "Z28 / 5.7i", expected: "Z28" },
  { trim: "Base / 3.8L", expected: "Base" },
  { trim: "XLT / 3.5 EcoBoost", expected: "XLT" },
];

// Simple implementation to test
const ENGINE_PATTERNS = [
  /^\d+\.\d+[a-z]?$/i,
  /^\d+\.\d+L?$/i,
  /^V\d+$/i,
  /^\d+[a-z]?$/i,
  /^[A-Z]?\d{3,4}[a-z]?$/i,
  /^EcoBoost$/i,
  /^HEMI$/i,
  /^Turbo$/i,
];

const SUBMODEL_PATTERNS = [
  /Base/i, /Sport/i, /Limited/i, /XLT/i, /Lariat/i, /Z28/i, /SS$/i, /GT$/i,
  /Rubicon/i, /Sahara/i, /Denali/i, /Platinum/i, /Raptor/i, /SRT/i,
];

function isEngineLike(text) {
  if (!text) return false;
  const t = text.trim();
  for (const p of ENGINE_PATTERNS) {
    if (p.test(t)) return true;
  }
  if (/^[\d.]+$/.test(t) && t.length <= 5) return true;
  return false;
}

function isSubmodelLike(text) {
  if (!text) return false;
  const t = text.trim();
  for (const p of SUBMODEL_PATTERNS) {
    if (p.test(t)) return true;
  }
  return false;
}

function extractDisplayTrim(label) {
  if (!label) return "";
  const t = label.trim();
  if (isEngineLike(t) && !isSubmodelLike(t)) return "";

  if (t.includes("/") || t.includes(",")) {
    const parts = t.split(/[\/,]/).map(p => p.trim()).filter(Boolean);
    for (const part of parts) {
      if (isSubmodelLike(part) && !isEngineLike(part)) return part;
    }
    if (parts.length > 0 && !isEngineLike(parts[0])) return parts[0];
    return "";
  }

  if (isSubmodelLike(t)) return t;
  if (isEngineLike(t)) return "";
  return t;
}

console.log("Testing vehicleDisplay helper:\n");
let passed = 0;
let failed = 0;

testCases.forEach(tc => {
  const result = extractDisplayTrim(tc.trim);
  const ok = result === tc.expected;
  if (ok) {
    passed++;
    console.log(`✓ "${tc.trim}" => "${result}"`);
  } else {
    failed++;
    console.log(`✗ "${tc.trim}" => "${result}" (expected "${tc.expected}")`);
  }
});

console.log(`\n${passed} passed, ${failed} failed`);

