import { NextResponse } from "next/server";

export const runtime = "edge";

// Common makes - covers ~95% of US market
const MAKES = [
  "Acura", "Alfa Romeo", "Aston Martin", "Audi", "Bentley", "BMW", "Buick",
  "Cadillac", "Chevrolet", "Chrysler", "Dodge", "Ferrari", "Fiat", "Ford",
  "Genesis", "GMC", "Honda", "Hyundai", "Infiniti", "Jaguar", "Jeep", "Kia",
  "Lamborghini", "Land Rover", "Lexus", "Lincoln", "Lotus", "Maserati",
  "Mazda", "McLaren", "Mercedes-Benz", "Mini", "Mitsubishi", "Nissan",
  "Polestar", "Porsche", "Ram", "Rivian", "Rolls-Royce", "Subaru", "Tesla",
  "Toyota", "Volkswagen", "Volvo"
].sort();

/**
 * GET /api/vehicles/makes?year=2005
 * 
 * Returns available makes (static list - API-independent).
 */
export async function GET() {
  return NextResponse.json(
    { results: MAKES },
    {
      headers: {
        "Cache-Control": "public, max-age=86400, s-maxage=86400",
      },
    }
  );
}

/**
 * Fitment Cache & Resilience Layer
 * 
 * Handles:
 * - In-memory caching of fitment profiles
 * - Request deduplication (one in-flight request per vehicle)
 * - Exponential backoff for 429 rate limits
 * - Graceful degradation on API failures
 */

// ─────────────────────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────────────────────

export type CachedFitment = {
  boltPattern?: string;
  centerBore?: number;
  tireSizes?: string[];
  wheelDiameterRangeIn?: [number | null, number | null];
  wheelWidthRangeIn?: [number | null, number | null];
  offsetRangeMm?: [number | null, number | null];
  staggered?: { isStaggered: boolean; reason?: string };
  vehicle?: {
    year: number;
    make: string;
    model: string;
    trim?: string;
    submodel?: string;
  };
  source: "wheelsize" | "wheelpros" | "cache" | "fallback";
  cachedAt: number;
  expiresAt: number;
};

type CacheEntry = {
  data: CachedFitment;
  fetchedAt: number;
  expiresAt: number;
};

type InFlightRequest = {
  promise: Promise<CachedFitment | null>;
  startedAt: number;
};

// ─────────────────────────────────────────────────────────────────────────────
// CONFIGURATION
// ─────────────────────────────────────────────────────────────────────────────

const CONFIG = {
  // Cache TTL (1 hour for successful fetches, 5 min for errors)
  CACHE_TTL_SUCCESS_MS: 60 * 60 * 1000,
  CACHE_TTL_ERROR_MS: 5 * 60 * 1000,

  // 429 backoff settings
  INITIAL_BACKOFF_MS: 5000,      // 5 seconds
  MAX_BACKOFF_MS: 5 * 60 * 1000, // 5 minutes
  BACKOFF_MULTIPLIER: 2,

  // Cooldown after 429 (don't retry for this period)
  COOLDOWN_AFTER_429_MS: 60 * 1000, // 1 minute

  // Max in-flight request age before considering stale
  MAX_INFLIGHT_AGE_MS: 30 * 1000,
};

// ─────────────────────────────────────────────────────────────────────────────
// STATE (module-level singletons)
// ─────────────────────────────────────────────────────────────────────────────

// LRU-ish cache (simple Map, could upgrade to proper LRU)
const cache = new Map<string, CacheEntry>();
const MAX_CACHE_SIZE = 500;

// In-flight request deduplication
const inFlight = new Map<string, InFlightRequest>();

// 429 rate limit state
let rateLimitState = {
  isLimited: false,
  limitedAt: 0,
  cooldownUntil: 0,
  consecutiveFailures: 0,
  currentBackoffMs: CONFIG.INITIAL_BACKOFF_MS,
};

// ─────────────────────────────────────────────────────────────────────────────
// CACHE KEY GENERATION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Generate a cache key for a vehicle fitment lookup.
 * Format: "year|make|model|modification" (lowercase, trimmed)
 */
export function makeCacheKey(
  year: string | number,
  make: string,
  model: string,
  modification?: string
): string {
  const parts = [
    String(year).trim(),
    String(make).trim().toLowerCase(),
    String(model).trim().toLowerCase(),
    modification ? String(modification).trim().toLowerCase() : "",
  ];
  return parts.join("|");
}

// ─────────────────────────────────────────────────────────────────────────────
// CACHE OPERATIONS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Get cached fitment data if available and not expired.
 */
export function getCached(key: string): CachedFitment | null {
  const entry = cache.get(key);
  if (!entry) return null;

  // Check expiration
  if (Date.now() > entry.expiresAt) {
    cache.delete(key);
    return null;
  }

  return { ...entry.data, source: "cache" };
}

/**
 * Store fitment data in cache.
 */
export function setCache(
  key: string,
  data: CachedFitment,
  ttlMs: number = CONFIG.CACHE_TTL_SUCCESS_MS
): void {
  const now = Date.now();

  // Evict oldest entries if cache is full
  if (cache.size >= MAX_CACHE_SIZE) {
    const oldestKey = cache.keys().next().value;
    if (oldestKey) cache.delete(oldestKey);
  }

  cache.set(key, {
    data: { ...data, cachedAt: now, expiresAt: now + ttlMs },
    fetchedAt: now,
    expiresAt: now + ttlMs,
  });
}

/**
 * Clear all cached data (useful for testing or forced refresh).
 */
export function clearCache(): void {
  cache.clear();
}

/**
 * Get cache statistics.
 */
export function getCacheStats(): {
  size: number;
  maxSize: number;
  rateLimited: boolean;
  cooldownRemainingMs: number;
} {
  return {
    size: cache.size,
    maxSize: MAX_CACHE_SIZE,
    rateLimited: rateLimitState.isLimited,
    cooldownRemainingMs: Math.max(0, rateLimitState.cooldownUntil - Date.now()),
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// RATE LIMIT HANDLING
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Check if we're currently in cooldown due to 429.
 */
export function isInCooldown(): boolean {
  return Date.now() < rateLimitState.cooldownUntil;
}

/**
 * Record a 429 response and update backoff state.
 */
export function record429(): void {
  const now = Date.now();
  rateLimitState.isLimited = true;
  rateLimitState.limitedAt = now;
  rateLimitState.consecutiveFailures++;

  // Exponential backoff
  rateLimitState.currentBackoffMs = Math.min(
    rateLimitState.currentBackoffMs * CONFIG.BACKOFF_MULTIPLIER,
    CONFIG.MAX_BACKOFF_MS
  );

  rateLimitState.cooldownUntil = now + rateLimitState.currentBackoffMs;

  console.warn(
    `[fitmentCache] 429 rate limit hit. Cooldown for ${rateLimitState.currentBackoffMs}ms. ` +
    `Consecutive failures: ${rateLimitState.consecutiveFailures}`
  );
}

/**
 * Record a successful API response and reset backoff.
 */
export function recordSuccess(): void {
  rateLimitState.isLimited = false;
  rateLimitState.consecutiveFailures = 0;
  rateLimitState.currentBackoffMs = CONFIG.INITIAL_BACKOFF_MS;
}

/**
 * Get current rate limit state for debugging.
 */
export function getRateLimitState(): typeof rateLimitState {
  return { ...rateLimitState };
}

// ─────────────────────────────────────────────────────────────────────────────
// REQUEST DEDUPLICATION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Check if there's already an in-flight request for this key.
 * Returns the existing promise if so, null otherwise.
 */
export function getInFlight(key: string): Promise<CachedFitment | null> | null {
  const entry = inFlight.get(key);
  if (!entry) return null;

  // Check if request is stale (took too long)
  if (Date.now() - entry.startedAt > CONFIG.MAX_INFLIGHT_AGE_MS) {
    inFlight.delete(key);
    return null;
  }

  return entry.promise;
}

/**
 * Register an in-flight request for deduplication.
 */
export function setInFlight(key: string, promise: Promise<CachedFitment | null>): void {
  inFlight.set(key, {
    promise,
    startedAt: Date.now(),
  });

  // Clean up after promise resolves
  promise.finally(() => {
    inFlight.delete(key);
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// FETCH WITH CACHING
// ─────────────────────────────────────────────────────────────────────────────

export type FetchFitmentOptions = {
  year: string | number;
  make: string;
  model: string;
  modification?: string;
  forceRefresh?: boolean;
};

/**
 * Fetch fitment data with caching, deduplication, and rate limit handling.
 * 
 * This is the main entry point for getting fitment data. It:
 * 1. Checks cache first
 * 2. Deduplicates concurrent requests
 * 3. Respects 429 cooldown
 * 4. Falls back gracefully on errors
 * 
 * @param fetcher - The actual fetch function to call if cache miss
 * @param options - Vehicle identification
 */
export async function fetchWithCache(
  fetcher: () => Promise<CachedFitment | null>,
  options: FetchFitmentOptions
): Promise<CachedFitment | null> {
  const key = makeCacheKey(options.year, options.make, options.model, options.modification);

  // 1. Check cache (unless force refresh)
  if (!options.forceRefresh) {
    const cached = getCached(key);
    if (cached) {
      return cached;
    }
  }

  // 2. Check for in-flight request (deduplication)
  const existing = getInFlight(key);
  if (existing) {
    return existing;
  }

  // 3. Check 429 cooldown
  if (isInCooldown()) {
    console.log(`[fitmentCache] In cooldown, returning null for ${key}`);
    return null;
  }

  // 4. Make the actual request
  const promise = (async (): Promise<CachedFitment | null> => {
    try {
      const result = await fetcher();

      if (result) {
        recordSuccess();
        setCache(key, result);
        return result;
      }

      return null;
    } catch (err: any) {
      // Check for 429
      if (err?.status === 429 || err?.message?.includes("429") || err?.message?.includes("rate limit")) {
        record429();
      }

      console.error(`[fitmentCache] Fetch error for ${key}:`, err?.message || err);
      return null;
    }
  })();

  // Register for deduplication
  setInFlight(key, promise);

  return promise;
}

// ─────────────────────────────────────────────────────────────────────────────
// FALLBACK DATA
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Create a minimal fallback fitment object when API is unavailable.
 * Used to ensure the UI can still render without raw engine text.
 */
export function createFallbackFitment(
  year: string | number,
  make: string,
  model: string
): CachedFitment {
  return {
    vehicle: {
      year: Number(year),
      make,
      model,
      // Note: NO trim/submodel - we don't have verified data
    },
    source: "fallback",
    cachedAt: Date.now(),
    expiresAt: Date.now() + CONFIG.CACHE_TTL_ERROR_MS,
  };
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { fitmentLabel, type Fitment } from "@/lib/fitment";

const YEARS = Array.from({ length: 26 }, (_, i) => String(new Date().getFullYear() - i));

async function fetchJson<T>(url: string): Promise<T> {
  const res = await fetch(url, { cache: "no-store" });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return (await res.json()) as T;
}

export function FitmentSelector({
  onComplete,
  provider,
  blank,
}: {
  onComplete?: (fitment: Fitment) => void;
  provider?: "wheelsize" | "wheelpros";
  /**
   * When true, the selector UI starts blank and ignores URL/localStorage prepopulation.
   * Intended for the mega menu SearchModal where we want an empty picker each time.
   */
  blank?: boolean;
} = {}) {
  const sp = useSearchParams();
  const pathname = usePathname();
  const router = useRouter();

  const fitment = useMemo<Fitment>(() => {
    if (blank) return {};
    const year = sp.get("year") ?? undefined;
    const make = sp.get("make") ?? undefined;
    const model = sp.get("model") ?? undefined;
    const trim = sp.get("trim") ?? undefined;
    const modification = sp.get("modification") ?? undefined;
    return { year, make, model, trim, modification };
  }, [sp, blank]);

  const [open, setOpen] = useState(false);
  const [draft, setDraft] = useState<Fitment>(fitment);

  useEffect(() => {
    if (blank) return;
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setDraft((d) => {
      const same = d.year === fitment.year && d.make === fitment.make && d.model === fitment.model && d.trim === fitment.trim;
      return same ? d : fitment;
    });
  }, [fitment, blank]);

  // If the URL has no fitment params but we have a saved fitment, restore it into the URL.
  // This prevents /wheels from showing an essentially "unfiltered" WheelPros list.
  useEffect(() => {
    if (blank) return;
    try {
      const hasUrlFitment = Boolean(fitment.year || fitment.make || fitment.model || fitment.modification);
      if (hasUrlFitment) return;

      const raw = localStorage.getItem("wt_fitment");
      if (!raw) return;
      const saved = JSON.parse(raw) as Partial<Fitment>;
      if (!saved?.year || !saved?.make || !saved?.model) return;

      apply({
        year: String(saved.year),
        make: String(saved.make),
        model: String(saved.model),
        trim: saved.trim ? String(saved.trim) : undefined,
        modification: saved.modification ? String(saved.modification) : undefined,
      });
    } catch {
      // ignore
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [blank]);

  useEffect(() => {
    if (blank) return;
    // persist last fitment (URL-applied)
    try {
      localStorage.setItem("wt_fitment", JSON.stringify(fitment));
    } catch {}
  }, [fitment, blank]);

  useEffect(() => {
    if (blank) return;
    // also persist draft as the user is selecting (so SearchModal can navigate without needing "Apply")
    try {
      localStorage.setItem("wt_fitment_draft", JSON.stringify(draft));
    } catch {}
  }, [draft, blank]);

  function apply(next: Fitment) {
    const params = new URLSearchParams(sp.toString());
    for (const k of ["year", "make", "model", "trim", "modification"] as const) {
      params.delete(k);
      const v = next[k];
      if (v) params.set(k, v);
    }

    const qs = params.toString();
    router.push(qs ? `${pathname}?${qs}` : pathname);
  }

  const [makes, setMakes] = useState<string[]>([]);
  const [models, setModels] = useState<string[]>([]);
  const [trims, setTrims] = useState<Array<{ value: string; label: string }>>([]);

  // Load makes when year changes
  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!draft.year) {
        setMakes([]);
        return;
      }
      try {
        const data = await fetchJson<{ results: string[] }>(`/api/vehicles/makes?year=${encodeURIComponent(draft.year)}`);
        if (!cancelled) setMakes(Array.isArray(data?.results) ? data.results : []);
      } catch {
        if (!cancelled) setMakes([]);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [draft.year]);

  // Load models when make changes
  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!draft.year || !draft.make) {
        setModels([]);
        return;
      }
      try {
        const qs = new URLSearchParams({ year: draft.year, make: draft.make });
        const data = await fetchJson<{ results: string[] }>(`/api/vehicles/models?${qs.toString()}`);
        if (!cancelled) setModels(Array.isArray(data?.results) ? data.results : []);
      } catch {
        if (!cancelled) setModels([]);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [draft.year, draft.make]);

  // Load trims when model changes
  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!draft.year || !draft.make || !draft.model) {
        setTrims([]);
        return;
      }
      try {
        const qs = new URLSearchParams({ year: draft.year, make: draft.make, model: draft.model });
        const url = provider === "wheelpros" ? `/api/wp/vehicles/submodels?${qs.toString()}` : `/api/vehicles/trims?${qs.toString()}`;
        const data = await fetchJson<{ results: Array<{ value: string; label: string }> }>(url);
        if (!cancelled) setTrims(Array.isArray(data?.results) ? data.results : []);
      } catch {
        if (!cancelled) setTrims([]);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [draft.year, draft.make, draft.model]);

  return (
    <div className="relative">
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="flex w-full items-center justify-between gap-3 rounded-xl border border-neutral-200 bg-white px-3 py-2 text-left"
        aria-haspopup="dialog"
        aria-expanded={open}
      >
        <div>
          <div className="text-[11px] font-semibold text-neutral-600">Vehicle</div>
          <div className="text-sm font-extrabold text-neutral-900">
            {fitmentLabel(fitment)}
          </div>
        </div>
        <div className="text-xs font-semibold text-neutral-600">Change</div>
      </button>

      {open ? (
        <div
          role="dialog"
          className="absolute left-0 right-0 top-[calc(100%+8px)] z-50 max-w-[min(520px,calc(100vw-2rem))] rounded-2xl border border-neutral-200 bg-white p-4 shadow-xl"
        >
          <div className="grid gap-3 grid-cols-2">
            <Select
              label="Year"
              value={draft.year ?? ""}
              onChange={(v) =>
                setDraft(() => ({ year: v || undefined, make: undefined, model: undefined, trim: undefined, modification: undefined }))
              }
              options={["", ...YEARS]}
            />
            <Select
              label="Make"
              value={draft.make ?? ""}
              onChange={(v) =>
                setDraft((d) => ({ ...d, make: v || undefined, model: undefined, trim: undefined, modification: undefined }))
              }
              options={["", ...makes]}
              disabled={!draft.year}
            />
            <Select
              label="Model"
              value={draft.model ?? ""}
              onChange={(v) =>
                setDraft((d) => ({ ...d, model: v || undefined, trim: undefined, modification: undefined }))
              }
              options={["", ...models]}
              disabled={!draft.make}
            />
            <Select
              label="Submodel"
              value={draft.modification ?? ""}
              onChange={(v) => {
                const sel = trims.find((t) => t.value === v);
                const next: Fitment = {
                  ...draft,
                  // For WheelPros submodels, store as a special modification token so downstream can detect it.
                  modification: v ? (provider === "wheelpros" ? `wp:${v}` : v) : undefined,
                  trim: sel?.label || undefined,
                };
                setDraft(next);

                // UX: once trim/modification is selected, immediately complete.
                // If parent provided onComplete, let it handle navigation (e.g. SearchModal -> /wheels?...).
                // Otherwise, apply to the current URL.
                if (next.modification) {
                  try {
                    localStorage.setItem("wt_fitment", JSON.stringify(next));
                  } catch {}

                  // Always apply to the current URL (keeps state consistent even if parent navigation fails).
                  apply(next);

                  setOpen(false);
                  onComplete?.(next);
                }
              }}
              options={[{ value: "", label: "" }, ...trims]}
              disabled={!draft.model}
              hint={draft.model && trims.length === 0 ? "Options list coming soon" : undefined}
            />
          </div>

          <div className="mt-4 flex items-center justify-between gap-2">
            <button
              type="button"
              onClick={() => {
                setOpen(false);
                setDraft(fitment);
              }}
              className="text-sm font-semibold text-neutral-600 hover:underline"
            >
              Cancel
            </button>
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => {
                  setDraft({});
                  apply({});
                  setOpen(false);
                }}
                className="rounded-xl border border-neutral-200 bg-white px-4 py-2 text-sm font-extrabold text-neutral-900"
              >
                Clear
              </button>
              <button
                type="button"
                onClick={() => {
                  apply(draft);
                  setOpen(false);
                }}
                className="rounded-xl bg-[var(--brand-red)] px-4 py-2 text-sm font-extrabold text-white hover:bg-[var(--brand-red-700)]"
              >
                Apply
              </button>
            </div>
          </div>
        </div>
      ) : null}
    </div>
  );
}

function Select({
  label,
  value,
  onChange,
  options,
  disabled,
  hint,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  options: Array<string | { value: string; label: string }>;
  disabled?: boolean;
  hint?: string;
}) {
  return (
    <label className="grid gap-1">
      <span className="text-xs font-semibold text-neutral-700">{label}</span>
      <select
        className="h-11 rounded-xl border border-neutral-200 bg-white px-3 text-sm font-semibold disabled:bg-neutral-50 disabled:text-neutral-400"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
      >
        {options.map((o) => {
          const opt = typeof o === "string" ? { value: o, label: o } : o;
          return (
            <option key={opt.value} value={opt.value}>
              {opt.label || `Select ${label}`}
            </option>
          );
        })}
      </select>
      {hint ? <span className="text-[11px] text-neutral-500">{hint}</span> : null}
    </label>
  );
}

import { NextResponse } from "next/server";

export const runtime = "nodejs";

const BASE_URL = "https://api.wheel-size.com/v2/";

function getApiKey(): string | null {
  return process.env.WHEELSIZE_API_KEY || null;
}

/**
 * GET /api/vehicles/models?year=2005&make=Cadillac
 * 
 * Returns available models from Wheel-Size API with package engine fallback.
 */
export async function GET(req: Request) {
  const url = new URL(req.url);
  const year = url.searchParams.get("year");
  const make = url.searchParams.get("make");

  if (!year || !make) {
    return NextResponse.json({ results: [] });
  }

  const apiKey = getApiKey();
  const makeSlug = make.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").replace(/-+/g, "-");

  // Try Wheel-Size API first
  if (apiKey) {
    try {
      const apiUrl = new URL("models/", BASE_URL);
      apiUrl.searchParams.set("user_key", apiKey);
      apiUrl.searchParams.set("make", makeSlug);
      apiUrl.searchParams.set("year", year);

      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 5000);

      const res = await fetch(apiUrl.toString(), {
        headers: { Accept: "application/json" },
        next: { revalidate: 86400 },
        signal: controller.signal,
      });

      clearTimeout(timeout);

      if (res.ok) {
        const data = await res.json();
        const models = data?.data || [];

        if (models.length > 0) {
          const results = models.map((m: any) => m?.name || m?.slug).filter(Boolean).sort();
          return NextResponse.json({ results }, {
            headers: { "Cache-Control": "public, max-age=3600, s-maxage=86400" },
          });
        }
      }

      // If rate limited or empty, fall through to package engine
      if (res.status !== 429) {
        console.log(`[models] Wheel-Size returned ${res.status}, trying fallback`);
      }
    } catch (err: any) {
      console.error(`[models] Wheel-Size error:`, err?.message);
    }
  }

  // Fallback to package engine
  const pkgUrl = process.env.PACKAGE_ENGINE_URL;
  if (pkgUrl) {
