import { extractDisplayTrim } from "./vehicleDisplay";

export type Fitment = {
  year?: string;
  make?: string;
  model?: string;
  trim?: string;
  // Wheel-Size modification id/slug (trim-specific fitment)
  modification?: string;
};

/**
 * Build a user-facing vehicle label.
 * Filters out engine text like "5.7i" - only shows real trim names.
 */
export function fitmentLabel(f: Fitment) {
  // Clean trim - filter out engine text
  const cleanTrim = extractDisplayTrim(f.trim ?? "");
  const parts = [f.year, f.make, f.model, cleanTrim].filter(Boolean);
  return parts.length ? parts.join(" ") : "Select vehicle";
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { extractDisplayTrim } from "@/lib/vehicleDisplay";

type Fitment = {
  year?: string;
  make?: string;
  model?: string;
  trim?: string;
  modification?: string;
};

type GarageItem = Fitment & {
  savedAt: number;
};

const KEY = "wt_garage";
const MAX = 5;

function readGarage(): GarageItem[] {
  try {
    const raw = localStorage.getItem(KEY);
    if (!raw) return [];
    const data = JSON.parse(raw);
    return Array.isArray(data) ? (data as GarageItem[]).filter(Boolean) : [];
  } catch {
    return [];
  }
}

function writeGarage(items: GarageItem[]) {
  try {
    localStorage.setItem(KEY, JSON.stringify(items.slice(0, MAX)));
  } catch {
    // ignore
  }
}

function fitmentKey(f: Fitment) {
  return [f.year, f.make, f.model, f.modification].filter(Boolean).join("|");
}

function label(f: Fitment) {
  // Never show raw engine text - extract clean submodel or omit
  const cleanTrim = extractDisplayTrim(f.trim ?? "");
  return [f.year, f.make, f.model, cleanTrim].filter(Boolean).join(" ");
}

function buildVehicleParams(f: Fitment) {
  const sp = new URLSearchParams();
  for (const k of ["year", "make", "model", "trim", "modification"] as const) {
    const v = f[k];
    if (v) sp.set(k, v);
  }
  return sp;
}

export function GarageWidget({
  type,
}: {
  type: "tires" | "wheels";
}) {
  const router = useRouter();
  const sp = useSearchParams();

  const [garage, setGarage] = useState<GarageItem[]>([]);
  useEffect(() => {
    setGarage(readGarage().sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0)).slice(0, MAX));
  }, []);

  const current = useMemo<Fitment>(() => {
    const fromUrl: Fitment = {
      year: sp.get("year") ?? undefined,
      make: sp.get("make") ?? undefined,
      model: sp.get("model") ?? undefined,
      trim: sp.get("trim") ?? undefined,
      modification: sp.get("modification") ?? undefined,
    };

    // If modification isn't present in the URL yet, fall back to saved fitment from localStorage.
    // This can happen when navigation/search happened before the URL was fully populated.
    if (!fromUrl.modification) {
      try {
        const raw = localStorage.getItem("wt_fitment") || localStorage.getItem("wt_fitment_draft");
        if (raw) {
          const saved = JSON.parse(raw) as any;
          return {
            year: fromUrl.year || saved?.year,
            make: fromUrl.make || saved?.make,
            model: fromUrl.model || saved?.model,
            trim: fromUrl.trim || saved?.trim,
            modification: saved?.modification,
          };
        }
      } catch {}
    }

    return fromUrl;
  }, [sp]);

  const hasVehicle = Boolean(current.year && current.make && current.model && current.modification);

  return (
    <div className="mt-3 flex flex-col gap-2 rounded-2xl border border-neutral-200 bg-white p-3">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="text-xs font-extrabold text-neutral-900">My Garage</div>
        <a href="/favorites" className="text-xs font-semibold text-neutral-600 hover:underline">
          Favorites
        </a>
        <button
          type="button"
          disabled={!hasVehicle}
          onClick={() => {
            const items = readGarage();
            const item: GarageItem = { ...current, savedAt: Date.now() };
            const k = fitmentKey(item);
            const next = [item, ...items.filter((x) => fitmentKey(x) !== k)]
              .sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0))
              .slice(0, MAX);
            writeGarage(next);
            setGarage(next);
          }}
          className={
            "h-9 rounded-xl px-3 text-xs font-extrabold " +
            (hasVehicle
              ? "bg-neutral-900 text-white hover:bg-neutral-800"
              : "cursor-not-allowed border border-neutral-200 bg-neutral-50 text-neutral-400")
          }
        >
          Save this vehicle
        </button>
      </div>

      <GarageList
        items={garage}
        onRemove={(f) => {
          const k = fitmentKey(f);
          const next = garage.filter((x) => fitmentKey(x) !== k);
          writeGarage(next);
          setGarage(next);
        }}
      />

      <div className="text-[11px] text-neutral-500">
        Saved in this browser (max {MAX}).
      </div>
    </div>
  );
}

function GarageList({
  items,
  onRemove,
}: {
  items: GarageItem[];
  onRemove: (f: Fitment) => void;
}) {
  const router = useRouter();

  if (!items.length) {
    return <div className="text-xs text-neutral-600">No saved vehicles yet.</div>;
  }

  return (
    <div className="flex flex-wrap gap-2">
      {items.map((it) => {
        const k = fitmentKey(it);
        const target = buildVehicleParams(it).toString();
        return (
          <div key={k} className="flex items-center gap-2 rounded-full border border-neutral-200 bg-white pl-3">
            <button
              type="button"
              onClick={() => {
                const base = typeof window !== "undefined" && window.location.pathname.startsWith("/tires") ? "/tires" : "/wheels";
                router.push(`${base}?${target}`);
              }}
              className="py-1 text-xs font-extrabold text-neutral-900 hover:underline"
              title="Search with this vehicle"
            >
              {label(it)}
            </button>
            <button
              type="button"
              onClick={() => onRemove(it)}
              className="rounded-full px-2 py-1 text-xs font-extrabold text-neutral-500 hover:bg-neutral-50 hover:text-neutral-900"
              title="Remove"
              aria-label={`Remove ${label(it)}`}
            >
              ×
            </button>
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { FitmentSelector } from "@/components/FitmentSelector";
import { vehicleSlug } from "@/lib/vehicleSlug";
import { extractDisplayTrim } from "@/lib/vehicleDisplay";
import tireSizes from "@/data/tire-sizes.json";

export type Mode = "vehicle" | "size";

function buildUrl(pathname: string, sp: URLSearchParams) {
  const qs = sp.toString();
  return qs ? `${pathname}?${qs}` : pathname;
}

function normalizeTireSize(width: number | null, aspect: number | null, rim: number | null) {
  if (!width || !aspect || !rim) return "";
  return `${width}/${aspect}R${rim}`;
}

function normalizeFlotationSize(dia: number | null, width: number | null, rim: number | null) {
  if (!dia || !width || !rim) return "";
  return `${dia}x${Number(width).toFixed(2)}R${rim}`;
}

function odMmFromMetric(width: number, aspect: number, rim: number) {
  return rim * 25.4 + 2 * (width * (aspect / 100));
}

function bestMetricForFlotation({
  flotation,
  metric,
}: {
  flotation: { dia: number; width: number; rim: number };
  metric: Array<{ width: number; aspect: number; rim: number; label: string }>;
}) {
  const targetOd = flotation.dia * 25.4;
  const targetWidthMm = flotation.width * 25.4;

  // Only consider metric sizes with same rim.
  const sameRim = metric.filter((m) => m.rim === flotation.rim);
  if (!sameRim.length) return null;

  let best: { label: string; score: number } | null = null;
  for (const m of sameRim) {
    const od = odMmFromMetric(m.width, m.aspect, m.rim);
    const odDiff = Math.abs(od - targetOd);
    const wDiff = Math.abs(m.width - targetWidthMm);
    // Heavily weight OD (fitment/speedo), lightly weight width.
    const score = odDiff * 2 + wDiff * 0.5;
    if (!best || score < best.score) best = { label: m.label, score };
  }
  return best?.label || null;
}

type GarageItem = {
  year?: string;
  make?: string;
  model?: string;
  trim?: string;
  modification?: string;
  savedAt?: number;
};

function buildVehicleParams(f: GarageItem) {
  const sp = new URLSearchParams();
  for (const k of ["year", "make", "model", "trim", "modification"] as const) {
    const v = (f as any)?.[k];
    if (v) sp.set(k, String(v));
  }
  return sp;
}

function garageLabel(f: GarageItem) {
  // Never show raw engine text - extract clean submodel or omit
  const cleanTrim = extractDisplayTrim(f.trim ?? "");
  return [f.year, f.make, f.model, cleanTrim].filter(Boolean).join(" ");
}

function GarageQuickPick({
  onPickTires,
  onPickWheels,
}: {
  onPickTires: (sp: URLSearchParams) => void;
  onPickWheels: (sp: URLSearchParams) => void;
}) {
  const [items, setItems] = useState<GarageItem[]>([]);

  useEffect(() => {
    try {
      const raw = localStorage.getItem("wt_garage");
      const data = raw ? JSON.parse(raw) : [];
      const arr = Array.isArray(data) ? (data as GarageItem[]) : [];
      setItems([...arr].sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0)).slice(0, 5));
    } catch {
      setItems([]);
    }
  }, []);


