function isValidDisplayLabel(value: string): boolean {
  if (!value) return false;
  const trimmed = value.trim();
  if (!trimmed) return false;
  if (isEngineCode(trimmed)) return false;
  if (isModificationId(trimmed)) return false;
  return true;
}

