/**
 * Create a new import job
 */
export async function createImportJob(
  source: string,
  yearStart?: number,
  yearEnd?: number,
  makes?: string[]
): Promise<string> {
  const job: NewFitmentImportJob = {
    source,
    yearStart: yearStart ?? null,
    yearEnd: yearEnd ?? null,
    makes: makes ?? null,
    status: "pending",
  };

  const [inserted] = await db
    .insert(fitmentImportJobs)
    .values(job)
    .returning({ id: fitmentImportJobs.id });

  return inserted.id;
}

/**
 * Update import job progress
 */
export async function updateImportJobProgress(
  jobId: string,
  progress: {
    status?: string;
    totalRecords?: number;
    processedRecords?: number;
    importedRecords?: number;
    skippedRecords?: number;
    errorCount?: number;
    lastError?: string;
  }
): Promise<void> {
  const updates: Record<string, unknown> = {};

  if (progress.status) {
    updates.status = progress.status;
    if (progress.status === "running" && !updates.startedAt) {
      updates.startedAt = new Date();
    }
    if (progress.status === "completed" || progress.status === "failed") {
      updates.completedAt = new Date();
    }
  }
  if (progress.totalRecords !== undefined) updates.totalRecords = progress.totalRecords;
  if (progress.processedRecords !== undefined) updates.processedRecords = progress.processedRecords;
  if (progress.importedRecords !== undefined) updates.importedRecords = progress.importedRecords;
  if (progress.skippedRecords !== undefined) updates.skippedRecords = progress.skippedRecords;
  if (progress.errorCount !== undefined) updates.errorCount = progress.errorCount;
  if (progress.lastError !== undefined) updates.lastError = progress.lastError;

  await db
    .update(fitmentImportJobs)
    .set(updates)
    .where(eq(fitmentImportJobs.id, jobId));
}

/**
 * Get import job status
 */
export async function getImportJob(jobId: string) {
  return db.query.fitmentImportJobs.findFirst({
    where: eq(fitmentImportJobs.id, jobId),
  });
}

// ============================================================================
// Import from Wheel-Size API (for batch operations)
// ============================================================================

const WHEELSIZE_API_BASE = "https://api.wheel-size.com/v2/";

interface WheelSizeImportOptions {
  yearStart: number;
  yearEnd: number;
  makes?: string[];
  apiKey: string;
  onProgress?: (current: number, total: number) => void;
}

/**
 * Import all fitments for a year range from Wheel-Size
 * This is for batch import jobs, not for runtime API calls
 */
export async function importFromWheelSize(
  jobId: string,
  options: WheelSizeImportOptions
): Promise<void> {
  const { yearStart, yearEnd, makes, apiKey, onProgress } = options;

  await updateImportJobProgress(jobId, { status: "running" });

  let totalProcessed = 0;
  let totalImported = 0;
  let totalSkipped = 0;
  let totalErrors = 0;

  try {
    // Get list of makes
    const makesToProcess = makes || await fetchWheelSizeMakes(apiKey);

    for (let year = yearStart; year <= yearEnd; year++) {
      for (const make of makesToProcess) {
        try {
          // Get models for this year/make
          const models = await fetchWheelSizeModels(apiKey, year, make);

          for (const model of models) {
            try {
              // Get modifications for this year/make/model
              const modifications = await fetchWheelSizeModifications(apiKey, year, make, model);

              for (const mod of modifications) {
                totalProcessed++;

                const result = await importWheelSizeFitment(
                  year,
                  make,
                  model,
                  mod,
                  undefined, // wheelData - would need separate API call
                  undefined, // tireData - would need separate API call
                  mod // fullPayload
                );

                if (result.action === "created" || result.action === "updated") {
                  totalImported++;
                } else if (result.action === "skipped") {
                  totalSkipped++;
                } else {
                  totalErrors++;
                }

                // Update progress every 100 records
                if (totalProcessed % 100 === 0) {
                  await updateImportJobProgress(jobId, {
                    processedRecords: totalProcessed,
                    importedRecords: totalImported,
                    skippedRecords: totalSkipped,
                    errorCount: totalErrors,
                  });
                  onProgress?.(totalProcessed, 0); // Total unknown in streaming mode
                }
              }
            } catch (modelErr: any) {
              console.error(`[import] Error processing ${year} ${make} ${model}:`, modelErr?.message);
              totalErrors++;
            }
          }
        } catch (makeErr: any) {
          console.error(`[import] Error processing ${year} ${make}:`, makeErr?.message);
          totalErrors++;
        }
      }
    }

    await updateImportJobProgress(jobId, {
      status: "completed",
      processedRecords: totalProcessed,
      importedRecords: totalImported,
      skippedRecords: totalSkipped,
      errorCount: totalErrors,
    });
  } catch (error: any) {
    await updateImportJobProgress(jobId, {
      status: "failed",
      lastError: error?.message,
      processedRecords: totalProcessed,
      importedRecords: totalImported,
      skippedRecords: totalSkipped,
      errorCount: totalErrors,
    });
    throw error;
  }
}

// ============================================================================
// Wheel-Size API Helpers
// ============================================================================

async function fetchWheelSizeMakes(apiKey: string): Promise<string[]> {
  const url = new URL("makes/", WHEELSIZE_API_BASE);
  url.searchParams.set("user_key", apiKey);

  const res = await fetch(url.toString());
  if (!res.ok) throw new Error(`Wheel-Size makes API failed: ${res.status}`);

  const data = await res.json();
  return (data?.data || []).map((m: any) => m.slug || m.name);
}

async function fetchWheelSizeModels(apiKey: string, year: number, make: string): Promise<string[]> {
  const url = new URL("models/", WHEELSIZE_API_BASE);
  url.searchParams.set("user_key", apiKey);
  url.searchParams.set("make", make);
  url.searchParams.set("year", String(year));

  const res = await fetch(url.toString());
  if (!res.ok) throw new Error(`Wheel-Size models API failed: ${res.status}`);

  const data = await res.json();
  return (data?.data || []).map((m: any) => m.slug || m.name);
}

async function fetchWheelSizeModifications(
  apiKey: string,
  year: number,
  make: string,
  model: string
): Promise<any[]> {
  const url = new URL("modifications/", WHEELSIZE_API_BASE);
  url.searchParams.set("user_key", apiKey);
  url.searchParams.set("make", make);
  url.searchParams.set("model", model);
  url.searchParams.set("year", String(year));

  const res = await fetch(url.toString());
  if (!res.ok) throw new Error(`Wheel-Size modifications API failed: ${res.status}`);

  const data = await res.json();
  return data?.data || [];
}

/**
 * Fitment Lookup Service (DB-First)
 * 
 * Priority order:
 * 1. Check database for cached fitment
 * 2. If not found or stale, call Wheel-Size API
 * 3. Import API response to database
 * 4. Apply any overrides
 * 5. Return normalized fitment
 */

import { db } from "./db";
import { vehicleFitments, fitmentOverrides } from "./schema";
import type { VehicleFitment, FitmentOverride } from "./schema";
import { eq, and, or, isNull, desc } from "drizzle-orm";
import { normalizeMake, normalizeModel, slugify } from "./keys";
import { importWheelSizeFitment } from "./importFitment";
import { applyOverrides } from "./applyOverrides";

// ============================================================================
// Types
// ============================================================================

export interface FitmentLookupResult {
  fitment: VehicleFitment | null;
  source: "db" | "api" | "not_found";
  apiCalled: boolean;
  overridesApplied: boolean;
}

export interface FitmentListResult {
  fitments: VehicleFitment[];
  source: "db" | "api" | "mixed";
  apiCalled: boolean;
}

interface WheelSizeApiConfig {
  apiKey: string;
  baseUrl?: string;
}

// Cache for API config to avoid repeated env lookups
let wheelSizeConfig: WheelSizeApiConfig | null = null;

function getWheelSizeConfig(): WheelSizeApiConfig | null {
  if (wheelSizeConfig) return wheelSizeConfig;

  const apiKey = process.env.WHEELSIZE_API_KEY;
  if (!apiKey) return null;

  wheelSizeConfig = {
    apiKey,
    baseUrl: process.env.WHEELSIZE_API_BASE_URL || "https://api.wheel-size.com/v2/",
  };

  return wheelSizeConfig;
}

// ============================================================================
// Single Fitment Lookup
// ============================================================================

/**
 * Get fitment for a specific vehicle modification
 * DB-first: checks database before calling API
 */
export async function getFitment(
  year: number,
  make: string,
  model: string,
  modificationId: string,
  options?: {
    forceRefresh?: boolean; // Skip DB, call API
    maxAgeDays?: number; // Re-fetch if older than this
  }
): Promise<FitmentLookupResult> {
  const normalizedMake = normalizeMake(make);
  const normalizedModel = normalizeModel(model);
  const normalizedModId = slugify(modificationId);

  // Step 1: Check database (unless forcing refresh)
  if (!options?.forceRefresh) {
    const dbFitment = await db.query.vehicleFitments.findFirst({
      where: and(
        eq(vehicleFitments.year, year),
        eq(vehicleFitments.make, normalizedMake),
        eq(vehicleFitments.model, normalizedModel),
        eq(vehicleFitments.modificationId, normalizedModId)
      ),
    });

    if (dbFitment) {
      // Check if data is stale
      const maxAgeDays = options?.maxAgeDays ?? 30;
      const maxAge = maxAgeDays * 24 * 60 * 60 * 1000;
      const isStale = Date.now() - dbFitment.updatedAt.getTime() > maxAge;

      if (!isStale) {
        // Apply overrides and return
        const withOverrides = await applyOverrides(dbFitment);
        return {
          fitment: withOverrides,
          source: "db",
          apiCalled: false,
          overridesApplied: withOverrides !== dbFitment,
        };
      }
      // Data is stale, fall through to API call
    }
  }

  // Step 2: Call Wheel-Size API
  const config = getWheelSizeConfig();
  if (!config) {
    return { fitment: null, source: "not_found", apiCalled: false, overridesApplied: false };
  }

  try {
    const apiData = await fetchWheelSizeModificationData(
      config,
      year,
      make,
      model,
      modificationId
    );

    if (!apiData) {
      return { fitment: null, source: "not_found", apiCalled: true, overridesApplied: false };
    }

    // Step 3: Import to database
    const importResult = await importWheelSizeFitment(
      year,
      make,
      model,
      apiData.modification,
      apiData.wheels,
      apiData.tires,
      apiData.fullPayload
    );

    if (!importResult.success || !importResult.fitmentId) {
      return { fitment: null, source: "not_found", apiCalled: true, overridesApplied: false };
    }

    // Step 4: Fetch the newly imported record
    const newFitment = await db.query.vehicleFitments.findFirst({
      where: eq(vehicleFitments.id, importResult.fitmentId),
    });

    if (!newFitment) {
      return { fitment: null, source: "not_found", apiCalled: true, overridesApplied: false };
    }

    // Step 5: Apply overrides and return
    const withOverrides = await applyOverrides(newFitment);
    return {
      fitment: withOverrides,
      source: "api",
      apiCalled: true,
      overridesApplied: withOverrides !== newFitment,
    };
  } catch (error: any) {
    console.error("[getFitment] API error:", error?.message);
    return { fitment: null, source: "not_found", apiCalled: true, overridesApplied: false };
  }
}

// ============================================================================
// List Fitments (Trims/Submodels)
// ============================================================================

/**
 * Get all fitments for a year/make/model
 * Used for trim selector dropdowns
 */
export async function listFitments(
  year: number,
  make: string,
  model: string,
  options?: {
    forceRefresh?: boolean;
  }
): Promise<FitmentListResult> {
  const normalizedMake = normalizeMake(make);
  const normalizedModel = normalizeModel(model);

  // Step 1: Check database
  if (!options?.forceRefresh) {
    const dbFitments = await db.query.vehicleFitments.findMany({
      where: and(
        eq(vehicleFitments.year, year),
        eq(vehicleFitments.make, normalizedMake),
        eq(vehicleFitments.model, normalizedModel)
      ),
      orderBy: [vehicleFitments.displayTrim],
    });

    if (dbFitments.length > 0) {
      // Apply overrides to all
      const withOverrides = await Promise.all(dbFitments.map(f => applyOverrides(f)));
      return {
        fitments: withOverrides,
        source: "db",
        apiCalled: false,
      };
    }
  }

  // Step 2: Call Wheel-Size API to get all modifications
  const config = getWheelSizeConfig();
  if (!config) {
    return { fitments: [], source: "not_found" as any, apiCalled: false };
  }

  try {
    const modifications = await fetchWheelSizeModifications(config, year, make, model);

    if (!modifications || modifications.length === 0) {
      return { fitments: [], source: "api", apiCalled: true };
    }

    // Import all modifications
    const importedFitments: VehicleFitment[] = [];

    for (const mod of modifications) {
      const result = await importWheelSizeFitment(
        year,
        make,
        model,
        mod,
        undefined,
        undefined,
        mod
      );

      if (result.success && result.fitmentId) {
        const fitment = await db.query.vehicleFitments.findFirst({
          where: eq(vehicleFitments.id, result.fitmentId),
        });
        if (fitment) {
          importedFitments.push(fitment);
        }
      }
    }

    // Apply overrides
    const withOverrides = await Promise.all(importedFitments.map(f => applyOverrides(f)));

    return {
      fitments: withOverrides,
      source: "api",
      apiCalled: true,
    };
  } catch (error: any) {
    console.error("[listFitments] API error:", error?.message);
    return { fitments: [], source: "api", apiCalled: true };
  }
}

// ============================================================================
// Quick Lookup (for selectors)
// ============================================================================

/**
 * Get trim options for selector (just value/label pairs)
 * This is the main entry point for the trim selector UI
 */
export async function getTrimOptions(
  year: number,
  make: string,
  model: string
): Promise<Array<{ value: string; label: string }>> {
  const result = await listFitments(year, make, model);

  // Dedupe by displayTrim
  const seen = new Set<string>();
  const options: Array<{ value: string; label: string }> = [];

  for (const fitment of result.fitments) {
    const labelKey = fitment.displayTrim.toLowerCase();
    if (!seen.has(labelKey)) {
      seen.add(labelKey);
      options.push({
        value: fitment.modificationId,
        label: fitment.displayTrim,
      });
    }
  }

  return options;
}

// ============================================================================
// Wheel-Size API Helpers
// ============================================================================

async function fetchWheelSizeModifications(
  config: WheelSizeApiConfig,
  year: number,
  make: string,
  model: string
): Promise<any[]> {
  const makeSlug = make.toLowerCase().replace(/[^a-z0-9]+/g, "-");
  const modelSlug = model.toLowerCase().replace(/[^a-z0-9]+/g, "-");

  const url = new URL("modifications/", config.baseUrl);
  url.searchParams.set("user_key", config.apiKey);
  url.searchParams.set("make", makeSlug);
  url.searchParams.set("model", modelSlug);
  url.searchParams.set("year", String(year));

  const res = await fetch(url.toString(), {
    headers: { Accept: "application/json" },
  });

  if (!res.ok) {
    throw new Error(`Wheel-Size modifications API failed: ${res.status}`);
  }

  const data = await res.json();
  return data?.data || [];
}

async function fetchWheelSizeModificationData(
  config: WheelSizeApiConfig,
  year: number,
  make: string,
  model: string,
  modificationId: string
): Promise<{
  modification: any;
  wheels?: any;
  tires?: any;
  fullPayload: any;
} | null> {
  // First get the modification details
  const modifications = await fetchWheelSizeModifications(config, year, make, model);
  const mod = modifications.find(m => m.slug === modificationId);

  if (!mod) return null;

  // TODO: Fetch wheel and tire data from separate endpoints if needed
  // For now, just return the modification
  return {
    modification: mod,
    fullPayload: mod,
  };
}

/**
 * Fitment Override Application
 * 
 * Applies manual overrides to fitment records.
 * Overrides are matched by scope (most specific wins):
 * 1. modification - exact match on year/make/model/modification
 * 2. model - matches all modifications for a year/make/model
 * 3. make - matches all models for a year/make
 * 4. year - matches all makes for a year
 * 5. global - matches everything
 */

import { db } from "./db";
import { fitmentOverrides } from "./schema";
import type { VehicleFitment, FitmentOverride } from "./schema";
import { eq, and, or, isNull, desc } from "drizzle-orm";
import { normalizeMake, normalizeModel, slugify } from "./keys";

// Override scope priority (higher = more specific = wins)
const SCOPE_PRIORITY: Record<string, number> = {
  modification: 5,
  model: 4,
  make: 3,
  year: 2,
  global: 1,
};

/**
 * Find all applicable overrides for a fitment record
 * Sorted by specificity (most specific first)
 */
export async function findApplicableOverrides(
  fitment: VehicleFitment
): Promise<FitmentOverride[]> {
  const normalizedMake = normalizeMake(fitment.make);
  const normalizedModel = normalizeModel(fitment.model);

  // Query for all potentially matching overrides
  const overrides = await db.query.fitmentOverrides.findMany({
    where: and(
      eq(fitmentOverrides.active, true),
      or(
        // Global overrides
        eq(fitmentOverrides.scope, "global"),
        // Year overrides
        and(
          eq(fitmentOverrides.scope, "year"),
          eq(fitmentOverrides.year, fitment.year)
        ),
        // Make overrides
        and(
          eq(fitmentOverrides.scope, "make"),
          or(
            isNull(fitmentOverrides.year),
            eq(fitmentOverrides.year, fitment.year)
          ),
          eq(fitmentOverrides.make, normalizedMake)
        ),
        // Model overrides
        and(
          eq(fitmentOverrides.scope, "model"),
          or(
            isNull(fitmentOverrides.year),
            eq(fitmentOverrides.year, fitment.year)
          ),
          eq(fitmentOverrides.make, normalizedMake),
          eq(fitmentOverrides.model, normalizedModel)
        ),
        // Modification overrides (most specific)
        and(
          eq(fitmentOverrides.scope, "modification"),
          eq(fitmentOverrides.year, fitment.year),
          eq(fitmentOverrides.make, normalizedMake),
          eq(fitmentOverrides.model, normalizedModel),
          eq(fitmentOverrides.modificationId, fitment.modificationId)
        )
      )
    ),
    orderBy: [desc(fitmentOverrides.createdAt)],
  });

  // Sort by scope priority (most specific first)
  return overrides.sort((a, b) => {
    const priorityA = SCOPE_PRIORITY[a.scope] || 0;
    const priorityB = SCOPE_PRIORITY[b.scope] || 0;
    return priorityB - priorityA;
  });
}

/**
 * Apply overrides to a fitment record
 * Returns a new record with overrides applied (original unchanged)
 */
export async function applyOverrides(fitment: VehicleFitment): Promise<VehicleFitment> {
  const overrides = await findApplicableOverrides(fitment);

  if (overrides.length === 0) {
    return fitment;
  }

  // Start with a copy
  const result: VehicleFitment = { ...fitment };

  // Apply overrides in order (most specific first, so they win)
  // But we iterate in reverse so less specific are applied first,
  // then more specific overwrite them
  for (const override of [...overrides].reverse()) {
    if (override.displayTrim !== null) {
      result.displayTrim = override.displayTrim;
    }
    if (override.boltPattern !== null) {
      result.boltPattern = override.boltPattern;
    }
    if (override.centerBoreMm !== null) {
      result.centerBoreMm = override.centerBoreMm;
    }
    if (override.threadSize !== null) {
      result.threadSize = override.threadSize;
    }
    if (override.seatType !== null) {
      result.seatType = override.seatType;
    }
    if (override.offsetMinMm !== null) {
      result.offsetMinMm = override.offsetMinMm;
    }
    if (override.offsetMaxMm !== null) {
      result.offsetMaxMm = override.offsetMaxMm;
    }
  }

  return result;
}

// ============================================================================
// Override Management
// ============================================================================

export interface CreateOverrideInput {
  scope: "global" | "year" | "make" | "model" | "modification";
  year?: number;
  make?: string;
  model?: string;
  modificationId?: string;
  displayTrim?: string;
  boltPattern?: string;
  centerBoreMm?: number;
  threadSize?: string;
  seatType?: string;
  offsetMinMm?: number;
  offsetMaxMm?: number;
  reason: string;
  createdBy: string;
}

/**
 * Create a new override
 */
export async function createOverride(input: CreateOverrideInput): Promise<string> {
  const [inserted] = await db
    .insert(fitmentOverrides)
    .values({
      scope: input.scope,
      year: input.year ?? null,
      make: input.make ? normalizeMake(input.make) : null,
      model: input.model ? normalizeModel(input.model) : null,
      modificationId: input.modificationId ? slugify(input.modificationId) : null,
      displayTrim: input.displayTrim ?? null,
      boltPattern: input.boltPattern ?? null,
      centerBoreMm: input.centerBoreMm ? String(input.centerBoreMm) : null,
      threadSize: input.threadSize ?? null,
      seatType: input.seatType ?? null,
      offsetMinMm: input.offsetMinMm ?? null,
      offsetMaxMm: input.offsetMaxMm ?? null,
      reason: input.reason,
      createdBy: input.createdBy,
      active: true,
    })
    .returning({ id: fitmentOverrides.id });

  return inserted.id;
}

/**
 * Deactivate an override (soft delete)
 */
export async function deactivateOverride(overrideId: string): Promise<void> {
  await db
    .update(fitmentOverrides)
    .set({ active: false, updatedAt: new Date() })
    .where(eq(fitmentOverrides.id, overrideId));
}

/**
 * List all active overrides
 */
export async function listOverrides(): Promise<FitmentOverride[]> {
  return db.query.fitmentOverrides.findMany({
    where: eq(fitmentOverrides.active, true),
    orderBy: [desc(fitmentOverrides.createdAt)],
  });
}

/**
 * Fitment Database - Public API
 * 
 * DB-first fitment system with Wheel-Size API fallback.
 */

// Core database
export { db, schema } from "./db";

// Types
export type {
  FitmentSource,
  FitmentSourceRecord,
  VehicleFitment,
  FitmentOverride,
  FitmentImportJob,
  OemWheelSize,
  OemTireSize,
  FitmentLookupParams,
  FitmentLookupResult,
  CanonicalKey,
} from "./types";

// Schema (for migrations)
export {
  fitmentSourceRecords,
  vehicleFitments,
  fitmentOverrides,
  fitmentImportJobs,
} from "./schema";

// Key generation
export {
  slugify,
  normalizeMake,
  normalizeModel,
  makeCanonicalKey,
  parseCanonicalKey,
  makeVehicleHash,
  makePayloadChecksum,
} from "./keys";

// Normalization
export {
  normalizeWheelSizeData,
  normalizeWheelProsData,
  normalizeManualFitment,
  createWheelSizeSourceRecord,
} from "./normalize";

// Import
export {
  importWheelSizeFitment,
  createImportJob,
  updateImportJobProgress,
  getImportJob,
  importFromWheelSize,
} from "./importFitment";

// Lookup (main entry points)
export {
  getFitment,
  listFitments,
  getTrimOptions,
} from "./getFitment";

// Overrides
export {
  findApplicableOverrides,
  applyOverrides,
  createOverride,
  deactivateOverride,
  listOverrides,
} from "./applyOverrides";

import { defineConfig } from "drizzle-kit";

export default defineConfig({
  schema: "./src/lib/fitment-db/schema.ts",
  out: "./drizzle/migrations",
  dialect: "postgresql",
  dbCredentials: {
    url: process.env.POSTGRES_URL!,
  },
  verbose: true,
  strict: true,
});

